// ── Icon data & rendering ─────────────────────────────────────────────────────
const GOLD='#c8a84b';

const ICON_SVG_B64 = {
  snail: '',
  footprint: '',
  rabbit: '',
  rocket: '',
  car: '',
  muscle: '',
  coffee: '',
  bed: '',
  work: '',
  plane: '',
  wheel: '',
  sunny: '',
  rainy: '',
  stormy: '',
  windy: '',
  snowy: '',
  cloudy: '',
};

const ICON_CACHE={};
function loadIcon(key){
  return new Promise(resolve=>{
    if(ICON_CACHE[key]){resolve();return;}
    const b64=ICON_SVG_B64[key];if(!b64){resolve();return;}
    const img=new Image();
    img.onload=()=>{
      const sz=512,off=document.createElement('canvas');
      off.width=sz;off.height=sz;
      const octx=off.getContext('2d');
      octx.drawImage(img,0,0,sz,sz);
      octx.globalCompositeOperation='source-in';
      octx.fillStyle=GOLD;
      octx.fillRect(0,0,sz,sz);
      ICON_CACHE[key]=off;resolve();
    };
    img.onerror=()=>resolve();
    img.src='data:image/svg+xml;base64,'+b64;
  });
}

const SYMBOL_ICON={
  snail:'snail', stroll:'footprint', quick:'rabbit', fast:'car', ultra:'rocket',
  bedroom:'bed', cafe:'coffee', drive:'wheel', travel:'plane', gym:'muscle', work:'work',
  sunny:'sunny', rainy:'rainy', stormy:'stormy', windy:'windy', snowy:'snowy', cloudy:'cloudy',
};

const REELS=[
  {name:'mood',   symbols:['sunny','rainy','stormy','windy','snowy','cloudy']},
  {name:'speed',  symbols:['snail','stroll','quick','fast','ultra']},
  {name:'setting',symbols:['bedroom','cafe','drive','travel','gym','work']},
];

const SYMBOL_LABELS={
  sunny:'SUNNY',rainy:'RAINY',stormy:'STORMY',windy:'WINDY',snowy:'SNOWY',cloudy:'CLOUDY',
  snail:'SNAIL',stroll:'STROLL',quick:'QUICK',fast:'FAST',ultra:'ULTRA',
  bedroom:'BEDROOM',cafe:'CAFE',drive:'DRIVE',travel:'TRAVEL',gym:'GYM',work:'WORK',
};
function englishLabel(sym){return SYMBOL_LABELS[sym];}

const PIXEL_GRID=40, PIXEL_THRESHOLD=30;
const PIXEL_ICON_CACHE={};
function getPixelatedIcon(key){
  if(PIXEL_ICON_CACHE[key])return PIXEL_ICON_CACHE[key];
  const source=ICON_CACHE[key];if(!source)return null;
  const off=document.createElement('canvas');
  off.width=PIXEL_GRID;off.height=PIXEL_GRID;
  const octx=off.getContext('2d');
  octx.imageSmoothingEnabled=true;
  octx.drawImage(source,0,0,PIXEL_GRID,PIXEL_GRID);
  const imgData=octx.getImageData(0,0,PIXEL_GRID,PIXEL_GRID);
  const px=imgData.data;
  for(let i=0;i<px.length;i+=4){px[i+3]=px[i+3]>PIXEL_THRESHOLD?255:0;}
  octx.putImageData(imgData,0,0);
  PIXEL_ICON_CACHE[key]=off;
  return off;
}

function drawSymbol(ctx,name,cx,cy,size){
  const key=SYMBOL_ICON[name];
  const pixelIcon=key?getPixelatedIcon(key):null;
  if(!pixelIcon)return;
  const d=size*0.78;
  ctx.save();
  ctx.imageSmoothingEnabled=false;
  ctx.drawImage(pixelIcon,cx-d/2,cy-d/2,d,d);
  ctx.restore();
}

const allIconKeys=[...new Set(Object.values(SYMBOL_ICON).filter(Boolean))];
Promise.all(allIconKeys.map(loadIcon)).then(()=>reels.forEach(r=>r.draw()));

// ── Reel class ────────────────────────────────────────────────────────────────
class Reel{
  constructor(canvasEl,wrapEl,symbols){
    this.canvas=canvasEl;this.wrap=wrapEl;this.ctx=canvasEl.getContext('2d');
    this.symbols=symbols;this.itemH=0;this.offset=0;this.spinning=false;this.resize();
  }
  resize(){
    const rect=this.wrap.getBoundingClientRect(),dpr=window.devicePixelRatio||1;
    this.w=rect.width;this.h=rect.height;
    this.canvas.width=this.w*dpr;this.canvas.height=this.h*dpr;
    this.canvas.style.height=this.h+'px';
    this.ctx.setTransform(dpr,0,0,dpr,0,0);
    this.itemH=this.h*0.5;
  }
  draw(){
    const ctx=this.ctx;ctx.clearRect(0,0,this.w,this.h);
    const n=this.symbols.length,itemH=this.itemH,bi=Math.floor(this.offset/itemH)-1;
    for(let i=bi;i<=bi+2;i++){
      const sym=this.symbols[((i%n)+n)%n];
      const y=i*itemH-this.offset+this.h/2;
      if(y<-itemH||y>this.h+itemH) continue;
      const alpha=Math.max(0.12,1-Math.abs(y-this.h/2)/(this.h*0.65));
      ctx.globalAlpha=alpha;
      drawSymbol(ctx,sym,this.w/2,y,Math.min(this.w,itemH)*0.62);
      ctx.globalAlpha=1;
    }
  }
  spinTo(targetIndex,duration,onDone,easeFn,loops){
    this.spinning=true;
    const n=this.symbols.length,itemH=this.itemH,startOffset=this.offset;
    loops=loops||3;
    const curMod=((Math.round(startOffset/itemH)%n)+n)%n;
    let delta=targetIndex-curMod;if(delta<=0)delta+=n;
    const targetOffset=startOffset+(loops*n+delta)*itemH;
    const startTime=performance.now(),ease=easeFn||(t=>1-Math.pow(1-t,3));
    const step=now=>{
      const t=Math.min((now-startTime)/duration,1);
      this.offset=startOffset+(targetOffset-startOffset)*ease(t);
      this.draw();
      if(t<1)requestAnimationFrame(step);
      else{this.offset=targetOffset;this.draw();this.spinning=false;if(onDone)onDone();}
    };
    requestAnimationFrame(step);
  }
}

let reels=[];
function initReels(){
  reels=REELS.map((r,i)=>{
    const reel=new Reel(document.getElementById('reel'+i),document.getElementById('reelWrap'+i),r.symbols);
    reel.offset=0;reel.draw();return reel;
  });
}
window.addEventListener('resize',()=>reels.forEach(r=>{r.resize();r.draw();}));

// ── Sound ─────────────────────────────────────────────────────────────────────
let AC=null;
function getAC(){if(!AC){try{AC=new(window.AudioContext||window.webkitAudioContext)();}catch(e){}}return AC;}
function playLeverPull(){const ac=getAC();if(!ac)return;const t=ac.currentTime;const o=ac.createOscillator(),g=ac.createGain();o.type='sawtooth';o.frequency.setValueAtTime(180,t);o.frequency.exponentialRampToValueAtTime(60,t+0.25);g.gain.setValueAtTime(0.001,t);g.gain.linearRampToValueAtTime(0.12,t+0.03);g.gain.exponentialRampToValueAtTime(0.001,t+0.3);o.connect(g);g.connect(ac.destination);o.start(t);o.stop(t+0.32);}
function playReelSpin(){const ac=getAC();if(!ac)return;const t=ac.currentTime;const bl=Math.ceil(ac.sampleRate*0.06),buf=ac.createBuffer(1,bl,ac.sampleRate),d=buf.getChannelData(0);for(let i=0;i<bl;i++)d[i]=(Math.random()*2-1)*0.3;const src=ac.createBufferSource();src.buffer=buf;const bp=ac.createBiquadFilter();bp.type='bandpass';bp.frequency.value=1400;bp.Q.value=4;const g=ac.createGain();g.gain.setValueAtTime(0.06,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.06);src.connect(bp);bp.connect(g);g.connect(ac.destination);src.start(t);src.stop(t+0.07);}
function playReelLock(pitch){const ac=getAC();if(!ac)return;const t=ac.currentTime;const o=ac.createOscillator(),g=ac.createGain();o.type='square';o.frequency.value=pitch;g.gain.setValueAtTime(0.001,t);g.gain.linearRampToValueAtTime(0.14,t+0.008);g.gain.exponentialRampToValueAtTime(0.001,t+0.14);o.connect(g);g.connect(ac.destination);o.start(t);o.stop(t+0.16);}
function playRevealChime(){const ac=getAC();if(!ac)return;const t=ac.currentTime;[523,659,784,1046].forEach((f,i)=>{const o=ac.createOscillator(),g=ac.createGain();o.type='triangle';o.frequency.value=f;g.gain.setValueAtTime(0,t+i*0.08);g.gain.linearRampToValueAtTime(0.16,t+i*0.08+0.02);g.gain.exponentialRampToValueAtTime(0.001,t+i*0.08+0.5);o.connect(g);g.connect(ac.destination);o.start(t+i*0.08);o.stop(t+i*0.08+0.55);});}

// ── Batch state ───────────────────────────────────────────────────────────────
const COOLDOWN_MS=30*60*1000;
let currentBatch=null;
let pulledIds=[];

function loadDeviceState(){try{return JSON.parse(localStorage.getItem('gacha_device_state')||'{}');}catch(e){return {};}}
function saveDeviceState(){localStorage.setItem('gacha_device_state',JSON.stringify({batchId:currentBatch?.batchId,pulledIds,sessionPlaylists}));}
function syncPulledIdsToBatch(){
  const stored=loadDeviceState();
  if(currentBatch&&stored.batchId===currentBatch.batchId){
    pulledIds=Array.isArray(stored.pulledIds)?stored.pulledIds:[];
    sessionPlaylists=Array.isArray(stored.sessionPlaylists)?stored.sessionPlaylists:[];
  } else {
    pulledIds=[];
    sessionPlaylists=[];
  }
}
function pullsRemaining(){return currentBatch?Math.max(0,currentBatch.playlists.length-pulledIds.length):0;}
function availablePlaylists(){return currentBatch?currentBatch.playlists.filter(p=>!pulledIds.includes(p.id)):[];}
function canPull(){return !!currentBatch&&!currentBatch.isGenerating&&pullsRemaining()>0;}
function cooldownRemainingMs(){return(currentBatch&&currentBatch.regenerationTriggerAt)?Math.max(0,currentBatch.regenerationTriggerAt+COOLDOWN_MS-Date.now()):0;}
function fmtCooldown(ms){const ts=Math.ceil(ms/1000),m=Math.floor(ts/60),sec=ts%60;return m+':'+String(sec).padStart(2,'0');}
function fmtDuration(sec){const h=Math.floor(sec/3600),m=Math.floor((sec%3600)/60);return h>0?h+'h '+m+'m':m+'m';}

async function fetchBatch(){
  try{
    const res=await fetch('/api/gacha/batch');
    if(!res.ok)throw new Error('bad response');
    const data=await res.json();
    const isNewBatch=!currentBatch||currentBatch.batchId!==data.batchId;
    currentBatch=data;
    if(isNewBatch){
      await flushPendingRatings();
      syncPulledIdsToBatch();
      renderSessionList();
      if(window._notifNewBatch) window._notifNewBatch(data.batchId);
    }
    updateStatusUI();
  }catch(e){console.error('Failed to fetch gacha batch:',e.message);}
}

async function flushPendingRatings(){
  // Collect all pending rating keys from localStorage
  const pending = [];
  for(let i = 0; i < localStorage.length; i++){
    const key = localStorage.key(i);
    if(!key?.startsWith('pending:')) continue;
    try{
      const rating = JSON.parse(localStorage.getItem(key));
      if(rating) pending.push(rating);
    } catch(e) {}
  }
  if(!pending.length) return;

  console.log(`[gacha] Flushing ${pending.length} pending ratings...`);
  try{
    const res = await fetch('/api/ratings/flush', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ ratings: pending }),
    });
    if(res.ok){
      // Clear all pending keys from localStorage
      const keys = [];
      for(let i = 0; i < localStorage.length; i++){
        const key = localStorage.key(i);
        if(key?.startsWith('pending:')) keys.push(key);
      }
      keys.forEach(k => localStorage.removeItem(k));
      console.log(`[gacha] Flushed ${pending.length} ratings successfully`);
    } else {
      console.error('[gacha] Failed to flush ratings:', res.status);
    }
  } catch(e){
    console.error('[gacha] Flush error:', e.message);
  }
}

function updateStatusUI(){
  const btn=document.getElementById('btnSpin'),sub=document.getElementById('spinSubLabel'),badge=document.getElementById('pullsBadge');
  if(!currentBatch){badge.textContent='...';btn.disabled=true;sub.textContent='Loading…';return;}
  if(currentBatch.isGenerating){badge.textContent='...';btn.disabled=true;sub.textContent='Curating a new batch…';return;}
  if(!currentBatch.playlists.length){badge.textContent='0 LEFT';btn.disabled=true;sub.textContent='Add some albums first';return;}
  const rem=pullsRemaining();
  badge.textContent=rem+' LEFT';
  if(rem>0){btn.disabled=false;sub.textContent=rem+' pull'+(rem===1?'':'s')+' left';return;}
  const cd=cooldownRemainingMs();
  if(cd>0){btn.disabled=true;sub.textContent='Refills in '+fmtCooldown(cd);}
  else{btn.disabled=true;sub.textContent='Waiting for the batch to refresh…';}
}
setInterval(()=>{if(currentBatch)updateStatusUI();},1000);
setInterval(fetchBatch,20000);

