// ── Session & saved playlists ─────────────────────────────────────────────────
let sessionPlaylists=[];
let savedPlaylists=[];

async function fetchSaved(){
  try{const res=await fetch('/api/saved');if(res.ok)savedPlaylists=await res.json();}
  catch(e){}
}
function isSavedById(id){return savedPlaylists.some(p=>p.id===id);}

async function savePlaylist(playlist){
  try{
    const res=await fetch('/api/saved',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(playlist)});
    if(res.ok||res.status===409){await fetchSaved();renderSavedList();return true;}
  }catch(e){}
  return false;
}

async function unsavePlaylist(id){
  try{await fetch(`/api/saved/${id}`,{method:'DELETE'});await fetchSaved();renderSavedList();}catch(e){}
}

function renderPlaylistItem(p,inSavedTab=false){
  const item=document.createElement('div');item.className='playlist-item';
  const collageEl=document.createElement('div');collageEl.className='pl-collage';
  const removeBtn=inSavedTab?'<div class="pl-remove" title="Remove">✕</div>':'';
  item.innerHTML='<div class="pl-info"><div class="pl-name">'+p.name+'</div><div class="pl-meta">'+[p.mood,p.speed,p.setting].map(s=>englishLabel(s)).join(' · ')+' · '+p.trackCount+' tracks</div></div><div class="pl-play"><svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor"><polygon points="5 3 19 12 5 21 5 3"/></svg></div>'+removeBtn;
  item.insertBefore(collageEl, item.firstChild);
  buildMosaic(p.covers, 48, p.id).then(canvas=>{
    canvas.style.width='48px';canvas.style.height='48px';canvas.style.borderRadius='4px';
    collageEl.appendChild(canvas);
  });
  item.querySelector('.pl-play').addEventListener('click',e=>{e.stopPropagation();showReveal(p);});
  item.addEventListener('click',()=>showReveal(p));
  if(inSavedTab){
    item.querySelector('.pl-remove').addEventListener('click',async e=>{
      e.stopPropagation();
      await unsavePlaylist(p.id);
      showGachaToast('Removed');
    });
  }
  return item;
}
function renderSessionList(){
  const c=document.getElementById('sessionList');
  if(!sessionPlaylists.length){c.innerHTML='<div class="playlist-empty">No pulls yet this session.<br>Hit spin to generate one.</div>';return;}
  c.innerHTML='';sessionPlaylists.forEach(p=>c.appendChild(renderPlaylistItem(p,false)));
}
function renderSavedList(){
  const c=document.getElementById('savedList');
  if(!savedPlaylists.length){c.innerHTML='<div class="playlist-empty">No saved playlists yet.<br>Save one after spinning.</div>';return;}
  c.innerHTML='';savedPlaylists.forEach(p=>c.appendChild(renderPlaylistItem(p,true)));
}

// ── Reveal card ───────────────────────────────────────────────────────────────
let currentPlaylist=null;
function showReveal(p){
  currentPlaylist=p;
  document.getElementById('revealSlots').textContent=[p.mood,p.speed,p.setting].map(s=>englishLabel(s)).join(' · ');
  document.getElementById('revealName').textContent=p.name;
  document.getElementById('revealDesc').textContent=p.description;
  document.getElementById('revealMeta').textContent=p.trackCount+' tracks · '+fmtDuration(p.totalDuration);
  const col=document.getElementById('revealCollage');
  col.innerHTML='';
  col.style.display='block';
  buildMosaic(p.covers, 140, p.id).then(canvas=>{
    canvas.style.width='140px';canvas.style.height='140px';
    col.appendChild(canvas);
  });
  updateSaveButton(p.id);
  document.getElementById('revealOverlay').classList.add('visible');
  playRevealChime();
}
function updateSaveButton(id){
  const btn=document.getElementById('btnSaveReveal');
  const saved=isSavedById(id);
  btn.classList.toggle('saved',saved);
  btn.textContent=saved?'★ SAVED':'☆ SAVE';
}
function hideReveal(){document.getElementById('revealOverlay').classList.remove('visible');}
document.getElementById('btnCloseReveal').addEventListener('click',hideReveal);
document.getElementById('revealOverlay').addEventListener('click',e=>{if(e.target.id==='revealOverlay')hideReveal();});
document.getElementById('btnPlayReveal').addEventListener('click',()=>{
  if(!currentPlaylist){ console.error('btnPlayReveal: no currentPlaylist'); return; }
  if(!currentPlaylist.tracks || !currentPlaylist.tracks.length){ console.error('btnPlayReveal: playlist has no tracks', currentPlaylist); return; }
  try {
    const serialized = JSON.stringify(currentPlaylist);
    sessionStorage.setItem('gachaPlaylist', serialized);
    console.log('[gacha] stored playlist in sessionStorage, size:', serialized.length, 'bytes');
  } catch(e) {
    console.error('[gacha] sessionStorage.setItem failed:', e.message);
    return;
  }
  window.location.href=window.location.origin+'/play/gacha?skip=1';
});
document.getElementById('btnSaveReveal').addEventListener('click',async ()=>{
  if(!currentPlaylist)return;
  const btn=document.getElementById('btnSaveReveal');
  if(isSavedById(currentPlaylist.id)){
    await unsavePlaylist(currentPlaylist.id);
    updateSaveButton(currentPlaylist.id);
    showGachaToast('Removed from saved');
  }else{
    btn.textContent='SAVING…';btn.disabled=true;
    const ok=await savePlaylist(currentPlaylist);
    btn.disabled=false;
    if(ok){updateSaveButton(currentPlaylist.id);showGachaToast('Saved!');}
    else{updateSaveButton(currentPlaylist.id);showGachaToast('Save failed — server unreachable');}
  }
});

// ── Spin ──────────────────────────────────────────────────────────────────────
let spinInProgress=false;
document.getElementById('btnSpin').addEventListener('click',()=>{
  if(spinInProgress||!canPull())return;
  getAC();
  const choices=availablePlaylists();
  if(!choices.length){showGachaToast('No pulls left right now');return;}
  spinInProgress=true;playLeverPull();
  const chosen=choices[Math.floor(Math.random()*choices.length)];
  const targets=[
    Math.max(0,REELS[0].symbols.indexOf(chosen.mood)),
    Math.max(0,REELS[1].symbols.indexOf(chosen.speed)),
    Math.max(0,REELS[2].symbols.indexOf(chosen.setting)),
  ];
  const durations=[900,1300,2300];
  const loops=[6,8,14];
  let spinTimer=setInterval(playReelSpin,70);
  reels.forEach((reel,i)=>{
    reel.spinTo(targets[i],durations[i],async ()=>{
      playReelLock(440+i*110);
      if(i===reels.length-1){
        clearInterval(spinTimer);spinInProgress=false;
        pulledIds.push(chosen.id);
        sessionPlaylists.unshift(chosen);
        saveDeviceState();
        renderSessionList();
        updateStatusUI();
        if(pullsRemaining()===0){
          try{
            const res=await fetch('/api/gacha/complete',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({batchId:currentBatch.batchId})});
            if(res.ok){currentBatch=await res.json();updateStatusUI();}
          }catch(e){}
        }
        setTimeout(()=>showReveal(chosen),200);
      }
    },null,loops[i]);
  });
});

// ── Init ──────────────────────────────────────────────────────────────────────
// Move both nav buttons to <html> to escape body and gacha-screen transform
// clipping. The back button is inside .gacha-screen which has translateX,
// creating a containing block that clips position:absolute children at its edge.
(function escapeTransforms(){
  const edgeBtn = document.getElementById('gachaEdgeBtn');
  const backBtn = document.getElementById('gachaBackBtn');
  if(edgeBtn) document.documentElement.appendChild(edgeBtn);
  if(backBtn) document.documentElement.appendChild(backBtn);
})();

// Show the edge button only after the boot overlay is dismissed.
(function waitForBoot(){
  const overlay = document.getElementById('bootOverlay');
  const btn = document.getElementById('gachaEdgeBtn');
  if(!overlay || overlay.style.display === 'none'){
    btn.classList.add('ready'); return;
  }
  const obs = new MutationObserver(() => {
    if(overlay.style.display === 'none'){
      btn.classList.add('ready');
      obs.disconnect();
    }
  });
  obs.observe(overlay, {attributes:true, attributeFilter:['style']});
})();

fetchSaved().then(renderSavedList);
fetchBatch();
